{
  "executive_summary": "Design a unified API Gateway architecture that consolidates authentication, rate limiting, and traffic isolation into a single ingress layer, replacing the current fragmented per-service implementations. The gateway uses a three-listener topology to cleanly separate mobile, partner, and internal traffic while sharing common infrastructure for observability and routing.",

  "architecture": {
    "components": [
      {
        "name": "API Gateway (Edge)",
        "responsibility": "Single entry point for all external traffic. Handles TLS termination, authentication dispatch, rate limiting, request routing, and observability injection (trace IDs, request logging). Does NOT contain business logic.",
        "boundaries": "Owns the request lifecycle from ingress to upstream handoff. Never calls downstream databases directly. Stateless — all session/token state lives in external stores."
      },
      {
        "name": "Auth Service",
        "responsibility": "Centralized authentication and authorization. Issues and validates JWTs for mobile consumers, validates API keys for partner consumers, and manages partner key lifecycle (rotation, revocation). Exposes a fast token-introspection endpoint the gateway calls on every request.",
        "boundaries": "Owns identity and credentials. Does not know about business domain entities. The gateway calls it; services never call it directly for request-level auth (they trust the gateway-injected headers)."
      },
      {
        "name": "Rate Limiter (Shared Infrastructure)",
        "responsibility": "Enforces per-consumer rate limits using a sliding window algorithm backed by Redis. Supports distinct policy tiers: mobile (100 req/min per user), partner (1,000 req/min per API key), and an emergency global circuit breaker.",
        "boundaries": "Runs as a gateway plugin/filter, not a standalone service. State lives in Redis. Rate limit decisions are synchronous and sub-millisecond. No business logic."
      },
      {
        "name": "Webhook Dispatcher",
        "responsibility": "Reliable webhook delivery to partner endpoints. Consumes domain events from an internal message bus, transforms them into partner-facing payloads, signs them (HMAC-SHA256), delivers with exponential backoff retry (max 5 attempts over 24h), and logs delivery status.",
        "boundaries": "Owns outbound partner notifications only. Does not handle inbound requests. Decoupled from the gateway — reads from the event bus, not from HTTP traffic."
      },
      {
        "name": "Internal Service Mesh / Private Listener",
        "responsibility": "Handles east-west (service-to-service) traffic on a private network interface that is not exposed to the internet. Provides service discovery, mTLS between services, and internal load balancing.",
        "boundaries": "Physically isolated from external traffic via network segmentation (separate listener on a private subnet/VPC). No authentication layer — trust is established by network boundary + mTLS identity."
      },
      {
        "name": "Upstream Domain Services",
        "responsibility": "The actual logistics business services (tracking, booking, fleet management, etc.). After the gateway migration, these services shed all auth and rate-limiting code and trust the gateway-injected identity headers.",
        "boundaries": "Own business logic only. Receive pre-authenticated, rate-limited requests with identity context in headers (X-Consumer-Type, X-Consumer-ID, X-Partner-ID). Never exposed directly to the internet."
      }
    ],
    "interfaces": [
      {
        "from": "Mobile App",
        "to": "API Gateway (Public Listener :443)",
        "contract": "HTTPS + Bearer JWT in Authorization header. Gateway validates JWT via Auth Service introspection, applies mobile rate limit tier, routes to upstream service.",
        "coupling_type": "loose — standard OAuth2/JWT protocol"
      },
      {
        "from": "Partner Integration",
        "to": "API Gateway (Partner Listener :443/partner/*)",
        "contract": "HTTPS + API Key in X-API-Key header. Gateway validates key via Auth Service, applies partner rate limit tier, routes to upstream. Versioned API paths (/v1/, /v2/).",
        "coupling_type": "loose — API key is a standard pattern, versioned paths allow independent evolution"
      },
      {
        "from": "API Gateway",
        "to": "Auth Service",
        "contract": "Internal gRPC call: ValidateToken(token) → {consumer_id, consumer_type, scopes, partner_id?} and ValidateAPIKey(key) → {partner_id, scopes, rate_tier}. Response cached in gateway for 30s (JWTs) / 5min (API keys) to reduce latency.",
        "coupling_type": "tight (operational) — gateway depends on auth service availability. Mitigated by caching + circuit breaker."
      },
      {
        "from": "API Gateway",
        "to": "Rate Limiter (Redis)",
        "contract": "Lua script on Redis: SLIDING_WINDOW_CHECK(consumer_key, limit, window_seconds) → {allowed: bool, remaining: int, retry_after: int}. Consumer key format: mobile:{user_id} or partner:{api_key_hash}.",
        "coupling_type": "tight (operational) — mitigated by fail-open policy (if Redis is down, allow traffic with degraded rate limiting and alert)"
      },
      {
        "from": "API Gateway",
        "to": "Upstream Domain Services",
        "contract": "HTTP/2 with injected headers: X-Consumer-Type (mobile|partner|internal), X-Consumer-ID, X-Request-ID (trace), X-Partner-ID (if applicable). Services MUST reject requests missing X-Consumer-Type header as a defense-in-depth measure.",
        "coupling_type": "loose — services are unaware of auth mechanism, only consume identity headers"
      },
      {
        "from": "Internal Services",
        "to": "Internal Service Mesh (Private Listener :8443)",
        "contract": "mTLS with service identity certificates. No API key or JWT needed. Traffic never traverses public network. Service discovery via DNS or service registry.",
        "coupling_type": "loose — mTLS provides identity without application-level auth coupling"
      },
      {
        "from": "Domain Services",
        "to": "Webhook Dispatcher (via Event Bus)",
        "contract": "Domain events published to message bus (e.g., shipment.delivered, order.status_changed). Webhook Dispatcher subscribes, transforms to partner payload schema, delivers via HTTPS POST with HMAC-SHA256 signature in X-Webhook-Signature header.",
        "coupling_type": "very loose — asynchronous event-driven, no direct coupling"
      }
    ],
    "data_flow": "External request → DNS/LB → API Gateway (TLS termination) → Auth filter (JWT or API key validation via Auth Service, cached) → Rate limit filter (Redis sliding window check) → Route to upstream service with identity headers injected → Service processes request → Response flows back through gateway (no transformation, gateway is transparent on egress). For webhooks: Service emits domain event → Event bus → Webhook Dispatcher → Partner endpoint with retry.",
    "patterns_used": [
      {
        "pattern": "API Gateway / Backend for Frontend (BFF-lite)",
        "rationale": "Consolidates cross-cutting concerns (auth, rate limiting, observability) into a single layer. Eliminates the current inconsistency problem. The three-listener approach gives BFF-like separation without full BFF complexity."
      },
      {
        "pattern": "Sliding Window Rate Limiting",
        "rationale": "More accurate than fixed-window counters (avoids the burst-at-boundary problem). Redis-backed for horizontal scalability across multiple gateway instances."
      },
      {
        "pattern": "Token Introspection with Cache",
        "rationale": "Centralized auth validation avoids each service reimplementing JWT verification. Short-lived cache (30s for JWTs, 5min for API keys) balances latency against revocation propagation delay."
      },
      {
        "pattern": "Network-Level Isolation (Split Listeners)",
        "rationale": "Internal services are isolated by network topology, not by application-level auth. This is the strongest isolation guarantee — internal traffic physically cannot reach the public listener."
      },
      {
        "pattern": "Circuit Breaker on Auth/Rate Limit Dependencies",
        "rationale": "The gateway's operational dependencies (Auth Service, Redis) are single points of failure. Circuit breakers with sensible fallbacks (cached auth, fail-open rate limiting) prevent cascading failures."
      },
      {
        "pattern": "Outbox + Event Bus for Webhooks",
        "rationale": "Decouples webhook delivery from the request path. Guarantees at-least-once delivery with retry. Services don't need to know about partner webhook contracts."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Identity & Access",
        "classification": "generic",
        "aggregates": ["UserCredential", "PartnerAPIKey", "AccessPolicy"]
      },
      {
        "name": "Traffic Management",
        "classification": "supporting",
        "aggregates": ["RateLimitPolicy", "RouteConfiguration", "CircuitBreakerState"]
      },
      {
        "name": "Partner Integration",
        "classification": "supporting",
        "aggregates": ["WebhookSubscription", "DeliveryAttempt", "PartnerConfiguration"]
      },
      {
        "name": "Logistics (existing domain services)",
        "classification": "core",
        "aggregates": ["(existing — unchanged by this design)"]
      }
    ],
    "context_map": [
      {
        "upstream": "Identity & Access",
        "downstream": "Traffic Management (API Gateway)",
        "relationship": "Open Host Service — Auth Service exposes a clean introspection API that the gateway consumes. Gateway is a conformist to the auth contract."
      },
      {
        "upstream": "Logistics (domain services)",
        "downstream": "Partner Integration (Webhook Dispatcher)",
        "relationship": "Published Language — domain services emit standardized events, webhook dispatcher transforms them to partner-facing schemas via an Anti-Corruption Layer."
      },
      {
        "upstream": "Traffic Management",
        "downstream": "Logistics (domain services)",
        "relationship": "Customer-Supplier — gateway is supplier of pre-authenticated, rate-limited traffic. Domain services are downstream consumers that trust gateway-injected headers."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Single API Gateway rather than per-consumer-type BFF services",
      "gains": "Simpler operational footprint — one thing to deploy, monitor, and scale. Shared rate limiting infrastructure. Easier to enforce consistent policies.",
      "sacrifices": "Less flexibility to tailor API shapes per consumer type. If mobile and partner APIs diverge significantly in the future, the gateway routing config becomes complex.",
      "alternatives_considered": [
        "Full BFF pattern (separate gateway per consumer type) — rejected because the team is consolidating from fragmented auth, adding three gateways would increase operational burden. Can evolve to BFF later if needed.",
        "Service mesh only (Istio/Linkerd) — rejected because service meshes handle mTLS and observability well but are weak at application-level concerns like API key auth, per-user rate limiting, and webhook management."
      ]
    },
    {
      "decision": "Redis-backed rate limiting (centralized) rather than local in-memory counters",
      "gains": "Accurate rate limiting across multiple gateway instances. Consistent enforcement regardless of which instance handles the request.",
      "sacrifices": "Adds Redis as an operational dependency. ~1ms latency per rate limit check. Requires Redis HA setup.",
      "alternatives_considered": [
        "Local in-memory rate limiting — rejected because with multiple gateway instances, a user could get N × limit by hitting different instances.",
        "Distributed rate limiting with eventual consistency — considered but adds complexity for marginal benefit. Redis sliding window is proven and fast enough."
      ]
    },
    {
      "decision": "Fail-open rate limiting when Redis is unavailable",
      "gains": "Gateway stays available during Redis outages. Logistics operations (which are the core business) are not blocked by infrastructure failures in a supporting concern.",
      "sacrifices": "Temporary loss of rate limiting during Redis outage. Potential for abuse during that window.",
      "alternatives_considered": [
        "Fail-closed — rejected because blocking all traffic due to a rate limiter outage is disproportionate. The cure is worse than the disease.",
        "Local fallback counters — viable hybrid, but adds complexity. Recommend as a phase-2 enhancement."
      ]
    },
    {
      "decision": "Network isolation for internal services rather than a separate auth scheme",
      "gains": "Strongest possible isolation — no application-level bypass possible. Zero auth overhead for internal traffic. Simple mental model.",
      "sacrifices": "Requires proper network infrastructure (VPC, private subnets). Cannot easily expose internal services externally if needed later without re-architecting.",
      "alternatives_considered": [
        "Internal API keys or service tokens — rejected because it replicates the current fragmented auth problem, just for internal consumers.",
        "mTLS everywhere including external — overkill for mobile/partner consumers who use standard auth patterns."
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Consumer-type routing",
      "evolution_path": "The three-listener model can evolve into full BFF gateways if mobile and partner APIs diverge significantly. Each listener can be split into its own deployment without changing upstream services."
    },
    {
      "area": "Rate limit policies",
      "evolution_path": "Rate limit tiers are configuration, not code. New tiers (e.g., premium partners at 5,000 req/min) can be added by updating policy config. The sliding window algorithm handles any limit value."
    },
    {
      "area": "Auth mechanisms",
      "evolution_path": "The Auth Service abstraction means the gateway doesn't know how auth works internally. Can add OAuth2 PKCE, SAML, mutual TLS for partners, or any future auth scheme without touching the gateway or upstream services."
    },
    {
      "area": "Webhook event types",
      "evolution_path": "New domain events automatically become available for webhook delivery. Partners can subscribe to new event types without changes to the core services."
    }
  ],

  "rigidity_points": [
    {
      "area": "Gateway identity header contract (X-Consumer-Type, X-Consumer-ID)",
      "reason": "All upstream services depend on these headers for authorization decisions. Changing the header schema requires coordinated updates across all services. This rigidity is intentional — it's the stable interface contract that enables everything else to be flexible."
    },
    {
      "area": "Network topology (public vs private listeners)",
      "reason": "The security model depends on network isolation. Moving an internal service to be externally accessible requires deliberate architectural work, not just a config change. This rigidity protects the system."
    },
    {
      "area": "Redis as rate limit backend",
      "reason": "The sliding window Lua scripts are Redis-specific. Migrating to a different store would require reimplementation. Acceptable because Redis is a proven, commodity solution for this use case."
    }
  ],

  "risks": [
    {
      "risk": "API Gateway becomes a single point of failure for all external traffic",
      "severity": "critical",
      "mitigation": "Deploy gateway as a horizontally scaled, stateless cluster (minimum 3 instances) behind a cloud load balancer with health checks. Ensure zero-downtime deployments via rolling updates. Monitor p99 latency and error rates with alerting."
    },
    {
      "risk": "Auth Service introspection latency adds to every request",
      "severity": "high",
      "mitigation": "Cache introspection results at the gateway (30s for JWTs, 5min for API keys). Use gRPC for low-latency internal calls. Circuit breaker with fallback to cached results if Auth Service is degraded. Target: <5ms p99 for cached, <20ms for uncached."
    },
    {
      "risk": "Migration period with mixed auth: some services still doing their own auth while gateway is being rolled out",
      "severity": "high",
      "mitigation": "Phased rollout: (1) Deploy gateway in passthrough mode (routes traffic, no auth enforcement). (2) Enable gateway auth per-service, one at a time. (3) Remove per-service auth only after gateway auth is verified. Use feature flags per service. Never remove old auth before new auth is proven."
    },
    {
      "risk": "Partner API key compromise with 10× higher rate limits",
      "severity": "high",
      "mitigation": "Support instant key revocation in Auth Service with cache invalidation push. Implement anomaly detection on partner traffic patterns. Provide partners with key rotation API. Log all partner requests for audit."
    },
    {
      "risk": "Redis outage disables rate limiting (fail-open policy)",
      "severity": "medium",
      "mitigation": "Redis Sentinel or Cluster for HA. Monitor Redis health aggressively. Alert on rate limiter bypass. Phase 2: add local in-memory fallback counters as a degraded-mode backstop."
    },
    {
      "risk": "Webhook delivery failures causing partner data staleness",
      "severity": "medium",
      "mitigation": "Exponential backoff retry (5 attempts over 24h). Dead letter queue for permanently failed deliveries. Partner-facing dashboard showing delivery status. Allow partners to replay missed webhooks via API."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Phase 1 (weeks 1-3): Deploy gateway in passthrough mode with observability. Stand up Auth Service with JWT validation and API key management. Phase 2 (weeks 3-5): Enable rate limiting and auth enforcement per-service, starting with the lowest-traffic service. Remove per-service auth code only after gateway auth is verified. Phase 3 (weeks 5-7): Webhook Dispatcher for partner integrations. Phase 4 (ongoing): Remove legacy per-service auth code, add anomaly detection, partner dashboard.",
    "files_to_create_or_modify": [
      "infrastructure/gateway/ — Gateway configuration (routes, rate limit policies, listener definitions)",
      "services/auth-service/ — New centralized auth service (JWT validation, API key management, introspection endpoint)",
      "infrastructure/redis/ — Rate limiter configuration and sliding window Lua scripts",
      "services/webhook-dispatcher/ — New webhook delivery service",
      "shared/middleware/ — Remove per-service auth middleware after migration (each upstream service)",
      "infrastructure/network/ — VPC/subnet configuration for public/private listener isolation",
      "docs/adr/ — Architecture Decision Record for gateway adoption"
    ],
    "patterns_to_follow": "Use an existing proven gateway (Kong, Envoy, AWS API Gateway, or Traefik) rather than building custom. Write rate limit policies as declarative configuration, not code. Use the gateway's native plugin system for auth and rate limiting filters. Keep the Auth Service as a thin, fast validation layer — no business logic. Use structured logging with correlation IDs (X-Request-ID) propagated from gateway through all services.",
    "pitfalls_to_avoid": [
      "Do NOT build a custom API gateway — use a proven open-source or managed solution. The team's time is better spent on logistics domain logic.",
      "Do NOT put business logic in the gateway. It handles cross-cutting concerns only. The moment you add a business rule to the gateway, you've created a god service.",
      "Do NOT do a big-bang migration. The phased approach (passthrough → enforce per-service → remove legacy) is critical for safety.",
      "Do NOT use the gateway for request/response transformation beyond header injection. Keep it transparent. If you need API translation, that belongs in a BFF or Anti-Corruption Layer.",
      "Do NOT share the same Redis instance for rate limiting and application caching. Rate limiting needs predictable latency and dedicated resources.",
      "Do NOT skip the 'services reject requests without X-Consumer-Type header' defense-in-depth check. Without it, a misconfigured network route could let unauthenticated traffic reach services."
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 85,
    "high_confidence_areas": [
      "Three-listener topology for consumer isolation — this is a well-proven pattern",
      "Centralized auth via gateway with token introspection — industry standard",
      "Redis sliding window for rate limiting — battle-tested approach",
      "Network isolation for internal services — strongest security guarantee",
      "Phased migration strategy — critical for safe rollout"
    ],
    "low_confidence_areas": [
      "Specific gateway product choice (Kong vs Envoy vs managed) — depends on team's infrastructure expertise, cloud provider, and existing tooling. Would need more context to recommend.",
      "Exact cache TTL values for auth introspection — 30s/5min are reasonable starting points but should be tuned based on observed revocation latency requirements and traffic patterns.",
      "Webhook Dispatcher scale requirements — depends on number of partners and event volume, which are not specified."
    ],
    "assumptions": [
      "The platform runs on cloud infrastructure with VPC/private subnet capability",
      "The team has operational capacity to manage Redis HA (or can use a managed Redis service)",
      "Mobile app uses standard OAuth2/JWT flows (not a custom auth protocol)",
      "Partner count is in the tens-to-hundreds range, not thousands (affects webhook dispatcher design)",
      "The team prefers adopting an existing gateway product over building custom"
    ]
  }
}

